import React, { useState } from "react";
import { useNavigate } from "react-router-dom";
import { useApp } from "../App";
import api from "../lib/api";
import { haptic } from "../lib/telegram";

export default function HomePage() {
  const { user, setUser } = useApp();
  const navigate = useNavigate();
  const [mode, setMode] = useState(null); // null | 'menu' | 'join'
  const [joinCode, setJoinCode] = useState("");
  const [bet, setBet] = useState(0);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");

  async function startGame(gameMode) {
    setLoading(true);
    setError("");
    try {
      const betAmount = gameMode === "bet" ? bet : 0;
      const res = await api.createGame(user.id, betAmount, gameMode);
      haptic.impact("medium");
      navigate(`/game/${res.code}`);
    } catch (e) {
      setError(e.message);
      haptic.notification("error");
    } finally {
      setLoading(false);
    }
  }

  async function joinGame() {
    if (!joinCode.trim()) return;
    setLoading(true);
    setError("");
    try {
      await api.joinGame(user.id, joinCode.trim().toUpperCase());
      haptic.impact("medium");
      navigate(`/game/${joinCode.trim().toUpperCase()}`);
    } catch (e) {
      setError(e.message);
      haptic.notification("error");
    } finally {
      setLoading(false);
    }
  }

  return (
    <div className="page animate-fade">
      {/* Header */}
      <div style={{ textAlign: "center", marginBottom: 32, paddingTop: 8 }}>
        <div style={{
          fontFamily: "Unbounded", fontSize: 32, fontWeight: 900,
          background: "linear-gradient(135deg, #7c5cfc, #a78bfa, #c4b5fd)",
          WebkitBackgroundClip: "text", WebkitTextFillColor: "transparent",
          letterSpacing: "-1px", marginBottom: 4
        }}>XO GAME</div>
        <div style={{ color: "var(--text2)", fontSize: 13 }}>
          Привет, <span style={{ color: "var(--accent3)", fontWeight: 600 }}>{user.first_name}</span>! 👋
        </div>
        <div style={{ marginTop: 8 }}>
          <span className="coins">{user.coins}</span>
          <span style={{ marginLeft: 8, color: "var(--text3)", fontSize: 12 }}>
            {user.rank.icon} {user.rank.name}
          </span>
        </div>
      </div>

      {/* Decorative board */}
      <div style={{
        display: "grid", gridTemplateColumns: "repeat(3,1fr)", gap: 8,
        maxWidth: 200, margin: "0 auto 32px",
      }}>
        {["✕","","○","","✕","","○","","✕"].map((s, i) => (
          <div key={i} style={{
            aspectRatio: "1", background: "var(--card2)",
            border: "1px solid var(--border)", borderRadius: 12,
            display: "flex", alignItems: "center", justifyContent: "center",
            fontSize: 22, color: s === "✕" ? "var(--accent2)" : "var(--gold)",
            fontFamily: "Unbounded",
          }}>{s}</div>
        ))}
      </div>

      {/* Mode selection */}
      {!mode && (
        <div style={{ display: "flex", flexDirection: "column", gap: 12 }}>
          <button className="btn btn-primary btn-lg btn-block animate-fade"
            onClick={() => { haptic.selection(); startGame("bot"); }}
            disabled={loading}
          >
            🤖 Играть с ботом
          </button>
          <button className="btn btn-secondary btn-lg btn-block"
            onClick={() => { haptic.selection(); setMode("friend"); }}
          >
            👥 Играть с другом
          </button>
          <button className="btn btn-gold btn-lg btn-block"
            onClick={() => { haptic.selection(); setMode("bet"); }}
          >
            💰 Игра на ставки
          </button>
          <button className="btn btn-outline btn-lg btn-block"
            onClick={() => { haptic.selection(); setMode("join"); }}
          >
            🔗 Войти по коду
          </button>
        </div>
      )}

      {/* Friend mode */}
      {mode === "friend" && (
        <div className="animate-fade" style={{ display: "flex", flexDirection: "column", gap: 12 }}>
          <p style={{ color: "var(--text2)", textAlign: "center", fontSize: 14 }}>
            Создай игру и отправь код другу
          </p>
          <button className="btn btn-primary btn-lg btn-block"
            onClick={() => startGame("friend")} disabled={loading}
          >
            {loading ? "Создаём..." : "🎮 Создать игру"}
          </button>
          <button className="btn btn-secondary btn-block"
            onClick={() => setMode(null)}
          >← Назад</button>
        </div>
      )}

      {/* Bet mode */}
      {mode === "bet" && (
        <div className="animate-fade" style={{ display: "flex", flexDirection: "column", gap: 12 }}>
          <p style={{ color: "var(--text2)", textAlign: "center", fontSize: 14 }}>
            Ставка (макс. <span className="coins">{user.coins}</span>)
          </p>
          <div style={{ display: "grid", gridTemplateColumns: "repeat(3,1fr)", gap: 8 }}>
            {[10, 25, 50, 100, 200, 500].map(v => (
              <button key={v}
                className={`btn ${bet === v ? "btn-primary" : "btn-secondary"}`}
                onClick={() => { haptic.selection(); setBet(v); }}
                disabled={v > user.coins}
              >🪙 {v}</button>
            ))}
          </div>
          <input className="input" type="number" placeholder="Своя сумма"
            value={bet || ""} min={0} max={user.coins}
            onChange={e => setBet(Math.min(Number(e.target.value), user.coins))}
          />
          <button className="btn btn-gold btn-lg btn-block"
            onClick={() => startGame("bet")} disabled={loading || bet <= 0}
          >
            {loading ? "Создаём..." : `💰 Играть на ${bet} монет`}
          </button>
          <button className="btn btn-secondary btn-block" onClick={() => setMode(null)}>← Назад</button>
        </div>
      )}

      {/* Join mode */}
      {mode === "join" && (
        <div className="animate-fade" style={{ display: "flex", flexDirection: "column", gap: 12 }}>
          <p style={{ color: "var(--text2)", textAlign: "center", fontSize: 14 }}>Введи код игры</p>
          <input className="input" placeholder="Код игры (6 символов)"
            value={joinCode} onChange={e => setJoinCode(e.target.value.toUpperCase())}
            maxLength={6} style={{ textAlign: "center", letterSpacing: 4, fontSize: 20, fontFamily: "Unbounded" }}
          />
          <button className="btn btn-primary btn-lg btn-block"
            onClick={joinGame} disabled={loading || joinCode.length < 6}
          >
            {loading ? "Входим..." : "🔗 Войти в игру"}
          </button>
          <button className="btn btn-secondary btn-block" onClick={() => setMode(null)}>← Назад</button>
        </div>
      )}

      {error && (
        <div style={{
          marginTop: 16, padding: 12, background: "rgba(239,68,68,0.1)",
          border: "1px solid rgba(239,68,68,0.3)", borderRadius: 10,
          color: "var(--red)", fontSize: 13, textAlign: "center"
        }}>{error}</div>
      )}
    </div>
  );
}
